final:
module RefModule(
    input clk,
    input rst,
    input serial_in,

    output reg [3:0] parallel_out
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst) 
            parallel_out <= 4'b0000;
        else 
            parallel_out <= {parallel_out[2:0], serial_in};
    end
endmodule
